import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    void testGetHeaderWhenHeaderIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set header to null
        Field headerField = CSVFormat.class.getDeclaredField("header");
        headerField.setAccessible(true);
        headerField.set(format, null);

        String[] header = format.getHeader();
        assertNull(header, "Expected null header when header field is null");
    }

    @Test
    void testGetHeaderReturnsCloneNotSameArray() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Set header to a non-null array via reflection
        Field headerField = CSVFormat.class.getDeclaredField("header");
        headerField.setAccessible(true);
        String[] originalHeader = new String[] {"col1", "col2", "col3"};
        headerField.set(format, originalHeader);

        String[] header = format.getHeader();
        assertNotNull(header, "Header should not be null");
        assertArrayEquals(originalHeader, header, "Header arrays should be equal in content");
        assertNotSame(originalHeader, header, "Returned header array should be a clone, not the same instance");
    }
}
